# Recursive fork-join nqueens.
#
# Canonical (TooManyCooks) implementation:
# ../../cpp/TooManyCooks/nqueens.cpp
# which was in turn adapted from libfork's benchmark.
#
# At each column, fork a child Weave task (spawn) for every valid queen
# placement, then sync their solution counts.
#
# The explicit {.gcsafe.} is required on Nim 2.x: gcsafety is not inferred for
# recursive procs, and the task wrapper generated by Weave's spawn demands it.

import std/[monotimes, times]
import weave
import benchutil

const nqueensWork = 14 # board size
const iterCount = 1

# answers[k] = number of solutions to the k-queens problem.
const answers: array[19, int] = [
  0, 1, 0, 0, 2, 10, 4, 40, 92, 352, 724, 2680, 14200, 73712, 365596, 2279184,
  14772512, 95815104, 666090624]

type Board = array[nqueensWork, int8]

proc checkAnswer(result: int) =
  if result != answers[nqueensWork]:
    echo "error: expected ", answers[nqueensWork], ", got ", result

proc nqueens(xMax: int, buf: Board): int {.gcsafe.} =
  if xMax == nqueensWork:
    return 1

  # Fork one child per valid placement; taskCount tracks how many of the (up
  # to nqueensWork) slots were actually used.
  var children: array[nqueensWork, Flowvar[int]]
  var taskCount = 0
  for y in 0 ..< nqueensWork:
    var valid = true
    for x in 0 ..< xMax:
      let p = int(buf[x])
      let d = xMax - x
      if y == p or y == p - d or y == p + d:
        valid = false
        break
    if not valid:
      continue
    var next = buf
    next[xMax] = int8(y)
    children[taskCount] = spawn nqueens(xMax + 1, next)
    inc taskCount

  var ret = 0
  for i in 0 ..< taskCount:
    ret += sync(children[i])
  result = ret

proc main() =
  let threadCount = threadCountArg(1)
  echo "threads: ", threadCount

  setWeaveThreads(threadCount)
  init(Weave)

  block:
    var buf: Board
    checkAnswer(nqueens(0, buf)) # warmup

  let start = getMonoTime()
  var res = 0
  for _ in 0 ..< iterCount:
    var buf: Board
    res = nqueens(0, buf)
    checkAnswer(res)
  let durUs = (getMonoTime() - start).inMicroseconds
  exit(Weave)
  echo "output: ", res

  echo "runs:"
  echo "  - iteration_count: ", iterCount
  echo "    duration: ", durUs, " us"
  echo "    max_rss: ", peakMemoryUsageKiB(), " KiB"

when isMainModule:
  main()
